from flask import Flask, request, jsonify, redirect
from werkzeug.security import generate_password_hash, check_password_hash
import secrets
import string
import time
import os

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(32))

# In-memory storage for authorization codes
auth_codes = {}
tokens = {}

# Mock user database
users = {
    "testuser": {
        "password_hash": generate_password_hash("testpass"),
        "client_id": "testclient",
        "client_secret": "testsecret"
    }
}

# Generate secure random code
def generate_code(length=48):
    alphabet = string.ascii_letters + string.digits + '-._~'
    return ''.join(secrets.choice(alphabet) for _ in range(length))

# Generate secure token
def generate_token(length=64):
    alphabet = string.ascii_letters + string.digits + '-._~'
    return ''.join(secrets.choice(alphabet) for _ in range(length))

@app.route('/authorize', methods=['GET'])
def authorize():
    client_id = request.args.get('client_id')
    redirect_uri = request.args.get('redirect_uri')
    response_type = request.args.get('response_type')
    
    if not all([client_id, redirect_uri, response_type]):
        return jsonify({"error": "Missing required parameters"}), 400
    
    if response_type != 'code':
        return jsonify({"error": "Unsupported response type"}), 400
    
    # In a real system, you would authenticate the user here
    # For this example, we'll assume the user is logged in
    user_id = "testuser"
    
    # Generate authorization code
    code = generate_code()
    auth_codes[code] = user_id
    
    # Redirect with code
    return redirect(f"{redirect_uri}?code={code}")

@app.route('/token', methods=['POST'])
def token():
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')
    grant_type = request.form.get('grant_type')
    code = request.form.get('code')
    
    if not all([client_id, client_secret, grant_type, code]):
        return jsonify({"error": "Missing required parameters"}), 400
    
    if grant_type != 'authorization_code':
        return jsonify({"error": "Unsupported grant type"}), 400
    
    # Validate client credentials
    if client_id not in users or not check_password_hash(users[client_id]["password_hash"], client_secret):
        return jsonify({"error": "Invalid client credentials"}), 401
    
    # Validate authorization code
    if code not in auth_codes:
        return jsonify({"error": "Invalid authorization code"}), 400
    
    # Get user ID from code
    user_id = auth_codes[code]
    
    # Generate access token
    token = generate_token()
    tokens[token] = {
        "user_id": user_id,
        "expires_at": time.time() + 3600  # 1 hour expiration
    }
    
    # Remove the authorization code (one-time use)
    del auth_codes[code]
    
    return jsonify({
        "access_token": token,
        "token_type": "Bearer",
        "expires_in": 3600
    })

if __name__ == '__main__':
    app.run(debug=False, host='0.0.0.0', port=5000)